import React, { useState } from 'react';
import { patientSignup } from '../../services/patientAuth';
import './PatientSignup.css';

const PatientSignup = ({ onSwitchToLogin }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    // Personal Information
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    phone: '',
    dateOfBirth: '',
    gender: '',

    // Medical Information
    bloodGroup: '',
    height: '',
    weight: '',
    allergies: '',
    currentMedications: '',
    emergencyContact: '',
    address: '',

    // Insurance Information (Optional)
    insuranceProvider: '',
    insuranceId: '',

    // Profile Image
    profileImage: null
  });

  const bloodGroups = ['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'];
  const genders = ['Male', 'Female', 'Other', 'Prefer not to say'];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({
          ...formData,
          profileImage: reader.result
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleNext = (e) => {
    e.preventDefault();
    console.log('Moving to step 2');
    setStep(2);
    window.scrollTo(0, 0);
  };

  const handlePrevious = (e) => {
    e.preventDefault();
    console.log('Moving back to step 1');
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log('🔵 SUBMIT BUTTON CLICKED - Step:', step);
    console.log('📦 Form Data:', formData);

    setLoading(true);
    setError('');

    try {
      console.log('🚀 Calling patientSignup...');
      const result = await patientSignup(formData);
      console.log('✅ Signup successful:', result);
      console.log('🔄 Switching to login page...');
      onSwitchToLogin();
    } catch (error) {
      console.error('❌ Signup error:', error);
      setError(error.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="patient-signup-container">
      <div className="signup-header">
        <h2>Create Patient Account</h2>
        <p>Join MediCare to manage your health records</p>
      </div>

      {error && (
        <div className="error-alert">
          <i className="fas fa-exclamation-circle"></i>
          {error}
        </div>
      )}

      {/* Progress Steps */}
      <div className="progress-steps">
        <div className={`progress-step ${step >= 1 ? 'active' : ''}`}>
          <div className="step-indicator">1</div>
          <span className="step-label">Personal Info</span>
        </div>
        <div className={`progress-line ${step >= 2 ? 'active' : ''}`}></div>
        <div className={`progress-step ${step >= 2 ? 'active' : ''}`}>
          <div className="step-indicator">2</div>
          <span className="step-label">Medical Info</span>
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        {/* Step 1: Personal Information */}
        {step === 1 && (
          <div className="form-step fade-in">
            <div className="step-header">
              <i className="fas fa-user-circle"></i>
              <h3>Personal Information</h3>
            </div>

            <div className="form-grid">
              <div className="form-group full-width">
                <label>Full Name</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="Enter your name"
                />
              </div>

              <div className="form-group full-width">
                <label>Email Address</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Enter your email"
                />
              </div>

              <div className="form-group half-width">
                <label>Password</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="Enter password"
                />
              </div>

              <div className="form-group half-width">
                <label>Confirm Password</label>
                <input
                  type="password"
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  placeholder="Confirm password"
                />
              </div>

              <div className="form-group third-width">
                <label>Phone Number</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder="Enter phone number"
                />
              </div>

              <div className="form-group third-width">
                <label>Date of Birth</label>
                <input
                  type="date"
                  name="dateOfBirth"
                  value={formData.dateOfBirth}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group third-width">
                <label>Gender</label>
                <select name="gender" value={formData.gender} onChange={handleChange}>
                  <option value="">Select Gender</option>
                  {genders.map(gender => (
                    <option key={gender} value={gender}>{gender}</option>
                  ))}
                </select>
              </div>

              <div className="form-group full-width">
                <label>Profile Photo</label>
                <div className="profile-upload-area">
                  <div className="profile-preview">
                    {formData.profileImage ? (
                      <img src={formData.profileImage} alt="Profile" className="preview-image" />
                    ) : (
                      <div className="preview-placeholder">
                        <i className="fas fa-camera"></i>
                      </div>
                    )}
                  </div>
                  <div className="upload-details">
                    <label className="upload-btn patient-upload-btn">
                      <i className="fas fa-upload"></i>
                      Choose Photo
                      <input
                        type="file"
                        accept="image/*"
                        onChange={handleImageChange}
                        className="file-input"
                      />
                    </label>
                  </div>
                </div>
              </div>
            </div>

            {/* Form Actions for Step 1 */}
            <div className="form-actions">
              <button type="button" className="btn btn-primary next-btn" onClick={handleNext}>
                Next Step <i className="fas fa-arrow-right"></i>
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Medical Information */}
        {step === 2 && (
          <div className="form-step fade-in">
            <div className="step-header">
              <i className="fas fa-notes-medical"></i>
              <h3>Medical Information</h3>
            </div>

            <div className="form-grid">
              <div className="form-group third-width">
                <label>Blood Group</label>
                <select 
                  name="bloodGroup" 
                  value={formData.bloodGroup} 
                  onChange={handleChange}
                >
                  <option value="">Select Blood Group</option>
                  {bloodGroups.map(group => (
                    <option key={group} value={group}>{group}</option>
                  ))}
                </select>
              </div>

              <div className="form-group third-width">
                <label>Height (cm)</label>
                <input
                  type="text"
                  name="height"
                  value={formData.height}
                  onChange={handleChange}
                  placeholder="e.g., 175"
                />
              </div>

              <div className="form-group third-width">
                <label>Weight (kg)</label>
                <input
                  type="text"
                  name="weight"
                  value={formData.weight}
                  onChange={handleChange}
                  placeholder="e.g., 70"
                />
              </div>

              <div className="form-group full-width">
                <label>Known Allergies</label>
                <textarea
                  name="allergies"
                  value={formData.allergies}
                  onChange={handleChange}
                  placeholder="List any allergies (e.g., Penicillin, Peanuts)"
                  rows="3"
                />
              </div>

              <div className="form-group full-width">
                <label>Current Medications</label>
                <textarea
                  name="currentMedications"
                  value={formData.currentMedications}
                  onChange={handleChange}
                  placeholder="List current medications with dosage"
                  rows="3"
                />
              </div>

              <div className="form-group full-width">
                <label>Emergency Contact</label>
                <input
                  type="text"
                  name="emergencyContact"
                  value={formData.emergencyContact}
                  onChange={handleChange}
                  placeholder="Name: Phone Number (e.g., John Doe: +1 234-567-8901)"
                />
              </div>

              <div className="form-group full-width">
                <label>Address</label>
                <textarea
                  name="address"
                  value={formData.address}
                  onChange={handleChange}
                  placeholder="Your full address"
                  rows="3"
                />
              </div>
            </div>

            {/* Insurance Information Section */}
            <div className="insurance-section">
              <div className="insurance-header">
                <i className="fas fa-shield-alt"></i>
                <h4>Insurance Information (Optional)</h4>
              </div>

              <div className="form-grid">
                <div className="form-group half-width">
                  <label>Insurance Provider</label>
                  <input
                    type="text"
                    name="insuranceProvider"
                    value={formData.insuranceProvider}
                    onChange={handleChange}
                    placeholder="e.g., Blue Cross"
                  />
                </div>

                <div className="form-group half-width">
                  <label>Insurance ID</label>
                  <input
                    type="text"
                    name="insuranceId"
                    value={formData.insuranceId}
                    onChange={handleChange}
                    placeholder="Insurance policy number"
                  />
                </div>
              </div>
            </div>

            {/* Form Actions for Step 2 */}
            <div className="form-actions">
              <button type="button" className="btn btn-outline patient-outline-btn" onClick={handlePrevious}>
                <i className="fas fa-arrow-left"></i> Previous
              </button>
              <button type="submit" className="btn btn-success patient-success-btn submit-btn" disabled={loading}>
                {loading ? (
                  <><i className="fas fa-spinner fa-spin"></i> Registering...</>
                ) : (
                  <><i className="fas fa-check-circle"></i> Complete Registration</>
                )}
              </button>
            </div>
          </div>
        )}
      </form>

      <div className="signup-footer">
        <p>Already have an account?</p>
        <button type="button" className="login-link patient-login-link" onClick={onSwitchToLogin}>
          Sign In <i className="fas fa-arrow-right"></i>
        </button>
      </div>
    </div>
  );
};

export default PatientSignup;
